/**
 * Analytics data models for the dashboard feature.
 *
 * These types define the shape of analytics data flowing through the system:
 * - Raw metrics are collected from orders and users
 * - Aggregated into summaries and time-series for dashboard consumption
 * - Filtered by time range and metric type
 */

// ─── Time Range ──────────────────────────────────────────────────────

/** Supported time range presets for analytics queries. */
export type TimeRangePreset = '24h' | '7d' | '30d' | '90d';

/** Explicit time range with start and end dates. */
export interface TimeRange {
  start: Date;
  end: Date;
}

/** Query filter — either a preset or an explicit range. */
export interface AnalyticsQuery {
  /** Use a preset like '7d' or supply a custom range. */
  preset?: TimeRangePreset;
  /** Custom range; takes precedence over preset if both provided. */
  range?: TimeRange;
}

// ─── Metric Types ────────────────────────────────────────────────────

/** Categories of metrics the analytics service can produce. */
export type MetricType = 'revenue' | 'orders' | 'users' | 'conversion';

/** A single point in a time series. */
export interface TimeSeriesPoint {
  timestamp: Date;
  value: number;
  /** Optional label for the data point (e.g., date string). */
  label?: string;
}

/** Summary statistics for a single metric. */
export interface MetricSummary {
  type: MetricType;
  /** Current value in the queried time range. */
  current: number;
  /** Value in the previous equivalent time range, for comparison. */
  previous: number;
  /** Percentage change: ((current - previous) / previous) * 100. */
  changePercent: number;
  /** Time-series data points within the range. */
  series: TimeSeriesPoint[];
}

// ─── Order Analytics ─────────────────────────────────────────────────

/** Breakdown of orders by status. */
export interface OrderStatusBreakdown {
  pending: number;
  confirmed: number;
  shipped: number;
  delivered: number;
  cancelled: number;
}

/** Top-performing product by revenue or quantity. */
export interface TopProduct {
  productId: string;
  name: string;
  totalRevenue: number;
  totalQuantity: number;
}

// ─── Dashboard ───────────────────────────────────────────────────────

/** Full dashboard payload returned by GET /api/analytics/dashboard. */
export interface DashboardData {
  /** The time range these results cover. */
  query: AnalyticsQuery;
  /** High-level metric summaries (revenue, orders, users, conversion). */
  metrics: MetricSummary[];
  /** Order breakdown by status within the queried range. */
  ordersByStatus: OrderStatusBreakdown;
  /** Top products by revenue in the queried range. */
  topProducts: TopProduct[];
  /** Timestamp when this snapshot was generated. */
  generatedAt: Date;
}

// ─── Route Request / Response Shapes ─────────────────────────────────

/** Query parameters for the dashboard endpoint. */
export interface DashboardRequest {
  preset?: TimeRangePreset;
  startDate?: string; // ISO 8601
  endDate?: string;   // ISO 8601
}

/** Query parameters for the single-metric endpoint. */
export interface MetricRequest {
  type: MetricType;
  preset?: TimeRangePreset;
  startDate?: string;
  endDate?: string;
}

/** Response wrapper with consistent structure. */
export interface AnalyticsResponse<T> {
  success: boolean;
  data: T;
  error?: string;
}

/**
 * AnalyticsService — Aggregates data from orders and users into dashboard metrics.
 *
 * This service queries OrderRepository and UserRepository to compute:
 * - Revenue, order count, user count, and conversion metrics
 * - Time-series breakdowns over configurable time ranges
 * - Order status distributions and top-product rankings
 *
 * Design notes for implementers:
 * - All aggregation happens in-memory over repository data. If the dataset
 *   grows, consider caching or pre-computed rollups.
 * - The service never mutates data — it is read-only.
 * - Time range resolution (parseQuery) normalises preset strings into
 *   concrete Date ranges so downstream methods don't need to care.
 */

import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeRange,
  TimeRangePreset,
  TopProduct,
} from '../models/analytics.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';

/** Map preset strings to millisecond durations. */
const PRESET_DURATIONS: Record<TimeRangePreset, number> = {
  '24h': 24 * 60 * 60 * 1000,
  '7d': 7 * 24 * 60 * 60 * 1000,
  '30d': 30 * 24 * 60 * 60 * 1000,
  '90d': 90 * 24 * 60 * 60 * 1000,
};

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  // ─── Public API ──────────────────────────────────────────────────

  /**
   * Return the full dashboard payload for the given query.
   *
   * Implementer: wire up each sub-method and combine results.
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Generating dashboard for range: ${JSON.stringify(query)}`);

    const range = this.resolveTimeRange(query);
    const resolvedQuery: AnalyticsQuery = { ...query, range };

    const [metrics, ordersByStatus, topProducts] = await Promise.all([
      this.getAllMetrics(range),
      this.getOrderStatusBreakdown(range),
      this.getTopProducts(range),
    ]);

    return {
      query: resolvedQuery,
      metrics,
      ordersByStatus,
      topProducts,
      generatedAt: new Date(),
    };
  }

  /**
   * Return a single metric summary for the given type and time range.
   */
  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
    this.logger.info(`Computing metric: ${type}`);
    const range = this.resolveTimeRange(query);
    return this.computeMetric(type, range);
  }

  /**
   * Return order counts grouped by status within the given range.
   */
  async getOrderStatusBreakdown(_range: TimeRange): Promise<OrderStatusBreakdown> {
    // TODO: Filter orders by range, group by status, count each.
    // Stub returns zeros — implement by querying orderRepository.findAll()
    // and filtering by createdAt within the range.
    this.logger.info('Computing order status breakdown');
    return {
      pending: 0,
      confirmed: 0,
      shipped: 0,
      delivered: 0,
      cancelled: 0,
    };
  }

  /**
   * Return the top products by revenue within the given range.
   *
   * @param _range - Time range to filter orders
   * @param _limit - Max number of products to return (default 10)
   */
  async getTopProducts(_range: TimeRange, _limit = 10): Promise<TopProduct[]> {
    // TODO: Flatten order items from orders within range,
    // aggregate by productId, sort by totalRevenue descending, slice to limit.
    this.logger.info('Computing top products');
    return [];
  }

  // ─── Private Helpers ─────────────────────────────────────────────

  /**
   * Resolve an AnalyticsQuery into a concrete TimeRange.
   * Custom range takes precedence; otherwise fall back to preset (default '7d').
   */
  private resolveTimeRange(query: AnalyticsQuery): TimeRange {
    if (query.range) {
      return query.range;
    }
    const preset = query.preset ?? '7d';
    const end = new Date();
    const start = new Date(end.getTime() - PRESET_DURATIONS[preset]);
    return { start, end };
  }

  /**
   * Compute all four metric summaries in parallel.
   */
  private async getAllMetrics(range: TimeRange): Promise<MetricSummary[]> {
    const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];
    return Promise.all(types.map((type) => this.computeMetric(type, range)));
  }

  /**
   * Compute a single metric's current value, previous-period value,
   * percent change, and time-series points.
   *
   * Implementer guide:
   * - 'revenue': sum of order totals in range; series = daily revenue sums
   * - 'orders': count of orders in range; series = daily order counts
   * - 'users': count of users created in range; series = daily new users
   * - 'conversion': orders / users ratio; series = daily ratios
   *
   * For the "previous" value, shift the range backward by its own duration
   * and recompute.
   */
  private async computeMetric(type: MetricType, _range: TimeRange): Promise<MetricSummary> {
    // TODO: Implement per-metric aggregation logic.
    // Stub returns a zeroed summary so the service compiles and tests can run.
    this.logger.info(`Computing metric stub: ${type}`);
    return {
      type,
      current: 0,
      previous: 0,
      changePercent: 0,
      series: [],
    };
  }
}

/**
 * Analytics route handlers.
 *
 * This module defines typed handler functions for the analytics API.
 * Since the project has no HTTP framework, these are pure functions
 * that accept parsed request data and return typed responses.
 * A future HTTP layer (Express, Fastify, etc.) can wrap these handlers.
 *
 * Route map:
 *   GET /api/analytics/dashboard?preset=7d          → handleGetDashboard
 *   GET /api/analytics/metrics/:type?preset=7d      → handleGetMetric
 *   GET /api/analytics/orders/status?preset=7d      → handleGetOrderStatus
 *   GET /api/analytics/products/top?preset=7d&limit=10 → handleGetTopProducts
 */

import type {
  AnalyticsQuery,
  AnalyticsResponse,
  DashboardData,
  DashboardRequest,
  MetricRequest,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeRangePreset,
  TopProduct,
} from '../models/analytics.js';
import type { AnalyticsService } from '../services/analytics.service.js';

const VALID_PRESETS = new Set<string>(['24h', '7d', '30d', '90d']);
const VALID_METRIC_TYPES = new Set<string>(['revenue', 'orders', 'users', 'conversion']);

/**
 * Parse raw query params into an AnalyticsQuery.
 * Returns an error string if validation fails, or the query if valid.
 */
function parseQueryParams(params: {
  preset?: string;
  startDate?: string;
  endDate?: string;
}): AnalyticsQuery | string {
  // Custom date range
  if (params.startDate || params.endDate) {
    if (!params.startDate || !params.endDate) {
      return 'Both startDate and endDate are required for custom ranges';
    }
    const start = new Date(params.startDate);
    const end = new Date(params.endDate);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
      return 'Invalid date format; use ISO 8601 (e.g., 2024-01-01T00:00:00Z)';
    }
    if (start >= end) {
      return 'startDate must be before endDate';
    }
    return { range: { start, end } };
  }

  // Preset
  if (params.preset && !VALID_PRESETS.has(params.preset)) {
    return `Invalid preset: ${params.preset}. Valid values: 24h, 7d, 30d, 90d`;
  }

  return { preset: (params.preset as TimeRangePreset) ?? '7d' };
}

/**
 * GET /api/analytics/dashboard
 *
 * Returns the full dashboard payload with all metric summaries,
 * order status breakdown, and top products.
 */
export async function handleGetDashboard(
  service: AnalyticsService,
  params: DashboardRequest,
): Promise<AnalyticsResponse<DashboardData | null>> {
  const queryOrError = parseQueryParams(params);
  if (typeof queryOrError === 'string') {
    return { success: false, data: null, error: queryOrError };
  }
  const data = await service.getDashboard(queryOrError);
  return { success: true, data };
}

/**
 * GET /api/analytics/metrics/:type
 *
 * Returns a single metric summary (revenue, orders, users, or conversion)
 * with current/previous values and time-series data.
 */
export async function handleGetMetric(
  service: AnalyticsService,
  params: MetricRequest,
): Promise<AnalyticsResponse<MetricSummary | null>> {
  if (!VALID_METRIC_TYPES.has(params.type)) {
    return {
      success: false,
      data: null,
      error: `Invalid metric type: ${params.type}. Valid values: revenue, orders, users, conversion`,
    };
  }

  const queryOrError = parseQueryParams(params);
  if (typeof queryOrError === 'string') {
    return { success: false, data: null, error: queryOrError };
  }

  const data = await service.getMetric(params.type as MetricType, queryOrError);
  return { success: true, data };
}

/**
 * GET /api/analytics/orders/status
 *
 * Returns order counts grouped by status.
 */
export async function handleGetOrderStatus(
  service: AnalyticsService,
  params: { preset?: string; startDate?: string; endDate?: string },
): Promise<AnalyticsResponse<OrderStatusBreakdown | null>> {
  const queryOrError = parseQueryParams(params);
  if (typeof queryOrError === 'string') {
    return { success: false, data: null, error: queryOrError };
  }

  const range = queryOrError.range ?? {
    start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
    end: new Date(),
  };
  const data = await service.getOrderStatusBreakdown(range);
  return { success: true, data };
}

/**
 * GET /api/analytics/products/top
 *
 * Returns top-performing products by revenue.
 */
export async function handleGetTopProducts(
  service: AnalyticsService,
  params: { preset?: string; startDate?: string; endDate?: string; limit?: number },
): Promise<AnalyticsResponse<TopProduct[] | null>> {
  const queryOrError = parseQueryParams(params);
  if (typeof queryOrError === 'string') {
    return { success: false, data: null, error: queryOrError };
  }

  const range = queryOrError.range ?? {
    start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
    end: new Date(),
  };
  const limit = params.limit && params.limit > 0 ? params.limit : 10;
  const data = await service.getTopProducts(range, limit);
  return { success: true, data };
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { AnalyticsQuery, DashboardData, MetricType } from '../../src/models/analytics.js';

describe('AnalyticsService', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('getDashboard', () => {
    it('should return a dashboard with all sections populated', async () => {
      const query: AnalyticsQuery = { preset: '7d' };
      const result: DashboardData = await service.getDashboard(query);

      expect(result.metrics).toHaveLength(4);
      expect(result.metrics.map((m) => m.type)).toEqual([
        'revenue',
        'orders',
        'users',
        'conversion',
      ]);
      expect(result.ordersByStatus).toBeDefined();
      expect(result.topProducts).toBeDefined();
      expect(result.generatedAt).toBeInstanceOf(Date);
    });

    it('should accept a custom time range', async () => {
      const query: AnalyticsQuery = {
        range: {
          start: new Date('2024-01-01'),
          end: new Date('2024-01-31'),
        },
      };
      const result = await service.getDashboard(query);

      expect(result.query.range).toBeDefined();
      expect(result.query.range?.start).toEqual(new Date('2024-01-01'));
    });

    it('should default to 7d when no preset or range given', async () => {
      const result = await service.getDashboard({});

      // The resolved range should be set
      expect(result.query.range).toBeDefined();
    });
  });

  describe('getMetric', () => {
    it('should return a metric summary for each valid type', async () => {
      const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];

      for (const type of types) {
        const result = await service.getMetric(type, { preset: '7d' });

        expect(result.type).toBe(type);
        expect(result).toHaveProperty('current');
        expect(result).toHaveProperty('previous');
        expect(result).toHaveProperty('changePercent');
        expect(result).toHaveProperty('series');
      }
    });
  });

  describe('getOrderStatusBreakdown', () => {
    it('should return counts for all statuses', async () => {
      const range = {
        start: new Date('2024-01-01'),
        end: new Date('2024-12-31'),
      };
      const result = await service.getOrderStatusBreakdown(range);

      expect(result).toHaveProperty('pending');
      expect(result).toHaveProperty('confirmed');
      expect(result).toHaveProperty('shipped');
      expect(result).toHaveProperty('delivered');
      expect(result).toHaveProperty('cancelled');
    });
  });

  describe('getTopProducts', () => {
    it('should return an array (empty with no data)', async () => {
      const range = {
        start: new Date('2024-01-01'),
        end: new Date('2024-12-31'),
      };
      const result = await service.getTopProducts(range);

      expect(Array.isArray(result)).toBe(true);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  handleGetDashboard,
  handleGetMetric,
  handleGetOrderStatus,
  handleGetTopProducts,
} from '../../src/routes/analytics.routes.js';

describe('Analytics Route Handlers', () => {
  let service: AnalyticsService;

  beforeEach(() => {
    const db = new Database();
    const orderRepo = new OrderRepository(db);
    const userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  describe('handleGetDashboard', () => {
    it('should return success with default preset', async () => {
      const result = await handleGetDashboard(service, {});

      expect(result.success).toBe(true);
      expect(result.data).toBeDefined();
      expect(result.data?.metrics).toHaveLength(4);
    });

    it('should reject invalid preset', async () => {
      const result = await handleGetDashboard(service, { preset: 'invalid' });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid preset');
    });

    it('should reject partial custom range', async () => {
      const result = await handleGetDashboard(service, { startDate: '2024-01-01' });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Both startDate and endDate');
    });

    it('should accept valid custom range', async () => {
      const result = await handleGetDashboard(service, {
        startDate: '2024-01-01T00:00:00Z',
        endDate: '2024-01-31T00:00:00Z',
      });

      expect(result.success).toBe(true);
    });
  });

  describe('handleGetMetric', () => {
    it('should return a metric for valid type', async () => {
      const result = await handleGetMetric(service, { type: 'revenue' });

      expect(result.success).toBe(true);
      expect(result.data?.type).toBe('revenue');
    });

    it('should reject invalid metric type', async () => {
      const result = await handleGetMetric(service, {
        type: 'invalid' as 'revenue',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid metric type');
    });
  });

  describe('handleGetOrderStatus', () => {
    it('should return status breakdown', async () => {
      const result = await handleGetOrderStatus(service, {});

      expect(result.success).toBe(true);
      expect(result.data).toHaveProperty('pending');
    });
  });

  describe('handleGetTopProducts', () => {
    it('should return top products array', async () => {
      const result = await handleGetTopProducts(service, {});

      expect(result.success).toBe(true);
      expect(Array.isArray(result.data)).toBe(true);
    });
  });
});

