+ * Analytics route handlers.
+ *
+ * This module defines typed handler functions for the analytics API.
+ * Since the project has no HTTP framework, these are pure functions
+ * that accept parsed request data and return typed responses.
+ * A future HTTP layer (Express, Fastify, etc.) can wrap these handlers.
+ *
+ * Route map:
+ *   GET /api/analytics/dashboard?preset=7d          → handleGetDashboard
+ *   GET /api/analytics/metrics/:type?preset=7d      → handleGetMetric
+ *   GET /api/analytics/orders/status?preset=7d      → handleGetOrderStatus
+ *   GET /api/analytics/products/top?preset=7d&limit=10 → handleGetTopProducts
+ */
+
+import type {
+  AnalyticsQuery,
+  AnalyticsResponse,
+  DashboardData,
+  DashboardRequest,
+  MetricRequest,
+  MetricSummary,
+  MetricType,
+  OrderStatusBreakdown,
+  TimeRangePreset,
+  TopProduct,
+} from '../models/analytics.js';
+import type { AnalyticsService } from '../services/analytics.service.js';
+
+const VALID_PRESETS = new Set<string>(['24h', '7d', '30d', '90d']);
+const VALID_METRIC_TYPES = new Set<string>(['revenue', 'orders', 'users', 'conversion']);
+
+/**
+ * Parse raw query params into an AnalyticsQuery.
+ * Returns an error string if validation fails, or the query if valid.
+ */
+function parseQueryParams(params: {
+  preset?: string;
+  startDate?: string;
+  endDate?: string;
+}): AnalyticsQuery | string {
+  // Custom date range
+  if (params.startDate || params.endDate) {
+    if (!params.startDate || !params.endDate) {
+      return 'Both startDate and endDate are required for custom ranges';
+    }
+    const start = new Date(params.startDate);
+    const end = new Date(params.endDate);
+    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
+      return 'Invalid date format; use ISO 8601 (e.g., 2024-01-01T00:00:00Z)';
+    }
+    if (start >= end) {
+      return 'startDate must be before endDate';
+    }
+    return { range: { start, end } };
+  }
+
+  // Preset
+  if (params.preset && !VALID_PRESETS.has(params.preset)) {
+    return `Invalid preset: ${params.preset}. Valid values: 24h, 7d, 30d, 90d`;
+  }
+
+  return { preset: (params.preset as TimeRangePreset) ?? '7d' };
+}
+
+/**
+ * GET /api/analytics/dashboard
+ *
+ * Returns the full dashboard payload with all metric summaries,
+ * order status breakdown, and top products.
+ */
+export async function handleGetDashboard(
+  service: AnalyticsService,
+  params: DashboardRequest,
+): Promise<AnalyticsResponse<DashboardData | null>> {
+  const queryOrError = parseQueryParams(params);
+  if (typeof queryOrError === 'string') {
+    return { success: false, data: null, error: queryOrError };
+  }
+  const data = await service.getDashboard(queryOrError);
+  return { success: true, data };
+}
+
+/**
+ * GET /api/analytics/metrics/:type
+ *
+ * Returns a single metric summary (revenue, orders, users, or conversion)
+ * with current/previous values and time-series data.
+ */
+export async function handleGetMetric(
+  service: AnalyticsService,
+  params: MetricRequest,
+): Promise<AnalyticsResponse<MetricSummary | null>> {
+  if (!VALID_METRIC_TYPES.has(params.type)) {
+    return {
+      success: false,
+      data: null,
+      error: `Invalid metric type: ${params.type}. Valid values: revenue, orders, users, conversion`,
+    };
+  }
+
+  const queryOrError = parseQueryParams(params);
+  if (typeof queryOrError === 'string') {
+    return { success: false, data: null, error: queryOrError };
+  }
+
+  const data = await service.getMetric(params.type as MetricType, queryOrError);
+  return { success: true, data };
+}
+
+/**
+ * GET /api/analytics/orders/status
+ *
+ * Returns order counts grouped by status.
+ */
+export async function handleGetOrderStatus(
+  service: AnalyticsService,
+  params: { preset?: string; startDate?: string; endDate?: string },
+): Promise<AnalyticsResponse<OrderStatusBreakdown | null>> {
+  const queryOrError = parseQueryParams(params);
+  if (typeof queryOrError === 'string') {
+    return { success: false, data: null, error: queryOrError };
+  }
+
+  const range = queryOrError.range ?? {
+    start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
+    end: new Date(),
+  };
+  const data = await service.getOrderStatusBreakdown(range);
+  return { success: true, data };
+}
+
+/**
+ * GET /api/analytics/products/top
+ *
+ * Returns top-performing products by revenue.
+ */
+export async function handleGetTopProducts(
+  service: AnalyticsService,
+  params: { preset?: string; startDate?: string; endDate?: string; limit?: number },
+): Promise<AnalyticsResponse<TopProduct[] | null>> {
+  const queryOrError = parseQueryParams(params);
+  if (typeof queryOrError === 'string') {
+    return { success: false, data: null, error: queryOrError };
+  }
+
+  const range = queryOrError.range ?? {
+    start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
+    end: new Date(),
+  };
+  const limit = params.limit && params.limit > 0 ? params.limit : 10;
+  const data = await service.getTopProducts(range, limit);
+  return { success: true, data };
+}

