+/**
+ * AnalyticsService — Aggregates data from orders and users into dashboard metrics.
+ *
+ * This service queries OrderRepository and UserRepository to compute:
+ * - Revenue, order count, user count, and conversion metrics
+ * - Time-series breakdowns over configurable time ranges
+ * - Order status distributions and top-product rankings
+ *
+ * Design notes for implementers:
+ * - All aggregation happens in-memory over repository data. If the dataset
+ *   grows, consider caching or pre-computed rollups.
+ * - The service never mutates data — it is read-only.
+ * - Time range resolution (parseQuery) normalises preset strings into
+ *   concrete Date ranges so downstream methods don't need to care.
+ */
+
+import type {
+  AnalyticsQuery,
+  DashboardData,
+  MetricSummary,
+  MetricType,
+  OrderStatusBreakdown,
+  TimeRange,
+  TimeRangePreset,
+  TopProduct,
+} from '../models/analytics.js';
+import type { OrderRepository } from '../repositories/order.repository.js';
+import type { UserRepository } from '../repositories/user.repository.js';
+import { Logger } from '../utils/logger.js';
+
+/** Map preset strings to millisecond durations. */
+const PRESET_DURATIONS: Record<TimeRangePreset, number> = {
+  '24h': 24 * 60 * 60 * 1000,
+  '7d': 7 * 24 * 60 * 60 * 1000,
+  '30d': 30 * 24 * 60 * 60 * 1000,
+  '90d': 90 * 24 * 60 * 60 * 1000,
+};
+
+export class AnalyticsService {
+  private logger = new Logger('AnalyticsService');
+
+  constructor(
+    private orderRepository: OrderRepository,
+    private userRepository: UserRepository,
+  ) {}
+
+  // ─── Public API ──────────────────────────────────────────────────
+
+  /**
+   * Return the full dashboard payload for the given query.
+   *
+   * Implementer: wire up each sub-method and combine results.
+   */
+  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
+    this.logger.info(`Generating dashboard for range: ${JSON.stringify(query)}`);
+
+    const range = this.resolveTimeRange(query);
+    const resolvedQuery: AnalyticsQuery = { ...query, range };
+
+    const [metrics, ordersByStatus, topProducts] = await Promise.all([
+      this.getAllMetrics(range),
+      this.getOrderStatusBreakdown(range),
+      this.getTopProducts(range),
+    ]);
+
+    return {
+      query: resolvedQuery,
+      metrics,
+      ordersByStatus,
+      topProducts,
+      generatedAt: new Date(),
+    };
+  }
+
+  /**
+   * Return a single metric summary for the given type and time range.
+   */
+  async getMetric(type: MetricType, query: AnalyticsQuery): Promise<MetricSummary> {
+    this.logger.info(`Computing metric: ${type}`);
+    const range = this.resolveTimeRange(query);
+    return this.computeMetric(type, range);
+  }
+
+  /**
+   * Return order counts grouped by status within the given range.
+   */
+  async getOrderStatusBreakdown(_range: TimeRange): Promise<OrderStatusBreakdown> {
+    // TODO: Filter orders by range, group by status, count each.
+    // Stub returns zeros — implement by querying orderRepository.findAll()
+    // and filtering by createdAt within the range.
+    this.logger.info('Computing order status breakdown');
+    return {
+      pending: 0,
+      confirmed: 0,
+      shipped: 0,
+      delivered: 0,
+      cancelled: 0,
+    };
+  }
+
+  /**
+   * Return the top products by revenue within the given range.
+   *
+   * @param _range - Time range to filter orders
+   * @param _limit - Max number of products to return (default 10)
+   */
+  async getTopProducts(_range: TimeRange, _limit = 10): Promise<TopProduct[]> {
+    // TODO: Flatten order items from orders within range,
+    // aggregate by productId, sort by totalRevenue descending, slice to limit.
+    this.logger.info('Computing top products');
+    return [];
+  }
+
+  // ─── Private Helpers ─────────────────────────────────────────────
+
+  /**
+   * Resolve an AnalyticsQuery into a concrete TimeRange.
+   * Custom range takes precedence; otherwise fall back to preset (default '7d').
+   */
+  private resolveTimeRange(query: AnalyticsQuery): TimeRange {
+    if (query.range) {
+      return query.range;
+    }
+    const preset = query.preset ?? '7d';
+    const end = new Date();
+    const start = new Date(end.getTime() - PRESET_DURATIONS[preset]);
+    return { start, end };
+  }
+
+  /**
+   * Compute all four metric summaries in parallel.
+   */
+  private async getAllMetrics(range: TimeRange): Promise<MetricSummary[]> {
+    const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];
+    return Promise.all(types.map((type) => this.computeMetric(type, range)));
+  }
+
+  /**
+   * Compute a single metric's current value, previous-period value,
+   * percent change, and time-series points.
+   *
+   * Implementer guide:
+   * - 'revenue': sum of order totals in range; series = daily revenue sums
+   * - 'orders': count of orders in range; series = daily order counts
+   * - 'users': count of users created in range; series = daily new users
+   * - 'conversion': orders / users ratio; series = daily ratios
+   *
+   * For the "previous" value, shift the range backward by its own duration
+   * and recompute.
+   */
+  private async computeMetric(type: MetricType, _range: TimeRange): Promise<MetricSummary> {
+    // TODO: Implement per-metric aggregation logic.
+    // Stub returns a zeroed summary so the service compiles and tests can run.
+    this.logger.info(`Computing metric stub: ${type}`);
+    return {
+      type,
+      current: 0,
+      previous: 0,
+      changePercent: 0,
+      series: [],
+    };
+  }
+}

