+import { describe, it, expect, beforeEach } from 'vitest';
+import { Database } from '../../src/utils/database.js';
+import { OrderRepository } from '../../src/repositories/order.repository.js';
+import { UserRepository } from '../../src/repositories/user.repository.js';
+import { AnalyticsService } from '../../src/services/analytics.service.js';
+import type { AnalyticsQuery, DashboardData, MetricType } from '../../src/models/analytics.js';
+
+describe('AnalyticsService', () => {
+  let db: Database;
+  let orderRepo: OrderRepository;
+  let userRepo: UserRepository;
+  let service: AnalyticsService;
+
+  beforeEach(() => {
+    db = new Database();
+    orderRepo = new OrderRepository(db);
+    userRepo = new UserRepository(db);
+    service = new AnalyticsService(orderRepo, userRepo);
+  });
+
+  describe('getDashboard', () => {
+    it('should return a dashboard with all sections populated', async () => {
+      const query: AnalyticsQuery = { preset: '7d' };
+      const result: DashboardData = await service.getDashboard(query);
+
+      expect(result.metrics).toHaveLength(4);
+      expect(result.metrics.map((m) => m.type)).toEqual([
+        'revenue',
+        'orders',
+        'users',
+        'conversion',
+      ]);
+      expect(result.ordersByStatus).toBeDefined();
+      expect(result.topProducts).toBeDefined();
+      expect(result.generatedAt).toBeInstanceOf(Date);
+    });
+
+    it('should accept a custom time range', async () => {
+      const query: AnalyticsQuery = {
+        range: {
+          start: new Date('2024-01-01'),
+          end: new Date('2024-01-31'),
+        },
+      };
+      const result = await service.getDashboard(query);
+
+      expect(result.query.range).toBeDefined();
+      expect(result.query.range?.start).toEqual(new Date('2024-01-01'));
+    });
+
+    it('should default to 7d when no preset or range given', async () => {
+      const result = await service.getDashboard({});
+
+      // The resolved range should be set
+      expect(result.query.range).toBeDefined();
+    });
+  });
+
+  describe('getMetric', () => {
+    it('should return a metric summary for each valid type', async () => {
+      const types: MetricType[] = ['revenue', 'orders', 'users', 'conversion'];
+
+      for (const type of types) {
+        const result = await service.getMetric(type, { preset: '7d' });
+
+        expect(result.type).toBe(type);
+        expect(result).toHaveProperty('current');
+        expect(result).toHaveProperty('previous');
+        expect(result).toHaveProperty('changePercent');
+        expect(result).toHaveProperty('series');
+      }
+    });
+  });
+
+  describe('getOrderStatusBreakdown', () => {
+    it('should return counts for all statuses', async () => {
+      const range = {
+        start: new Date('2024-01-01'),
+        end: new Date('2024-12-31'),
+      };
+      const result = await service.getOrderStatusBreakdown(range);
+
+      expect(result).toHaveProperty('pending');
+      expect(result).toHaveProperty('confirmed');
+      expect(result).toHaveProperty('shipped');
+      expect(result).toHaveProperty('delivered');
+      expect(result).toHaveProperty('cancelled');
+    });
+  });
+
+  describe('getTopProducts', () => {
+    it('should return an array (empty with no data)', async () => {
+      const range = {
+        start: new Date('2024-01-01'),
+        end: new Date('2024-12-31'),
+      };
+      const result = await service.getTopProducts(range);
+
+      expect(Array.isArray(result)).toBe(true);
+    });
+  });
+});
